namespace sv_38928f2df0784a0685fc3e956fc34fe3.Client.Auth;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_38928f2df0784a0685fc3e956fc34fe3.Client.Auth;

/// <summary>
/// Reads the persisted authentication state that was serialized by the server
/// during prerendering, so the user's identity survives the WebAssembly handoff.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask = _unauthenticated;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authenticationStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "Hardcoded"))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_38928f2df0784a0685fc3e956fc34fe3.Auth;

/// <summary>
/// Simulates a logged-in user with hardcoded claims. No real database needed.
/// </summary>
public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _state = Task.FromResult(CreateState());

    private static AuthenticationState CreateState()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, "Hardcoded");
        return new AuthenticationState(new ClaimsPrincipal(identity));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _state;
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_38928f2df0784a0685fc3e956fc34fe3.Client.Auth;

namespace sv_38928f2df0784a0685fc3e956fc34fe3.Auth;

/// <summary>
/// Serializes the server-side authentication state into PersistentComponentState
/// so the client-side (WebAssembly) AuthenticationStateProvider can pick it up.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly AuthenticationStateProvider _authProvider;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState state,
        AuthenticationStateProvider authProvider)
    {
        _state = state;
        _authProvider = authProvider;
        _subscription = state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authenticationStateTask ?? _authProvider.GetAuthenticationStateAsync();
        var result = await authState;
        var principal = result.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var userInfo = new UserInfo
            {
                Email = principal.FindFirst(System.Security.Claims.ClaimTypes.Email)?.Value ?? "",
                Roles = principal.FindAll(System.Security.Claims.ClaimTypes.Role).Select(c => c.Value).ToArray(),
            };

            _state.PersistAsJson(nameof(UserInfo), userInfo);
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

